const body = $('Code - Parse Query Context').first().json;
const message = body.message || '';
const history = Array.isArray(body.history) ? body.history.slice(-4) : [];

if (!message) throw new Error('message is required');

const scan = $('Postgres - Load Scan Context').first().json;
const metrics = $('Postgres - Load Metrics Context').first().json;
const sections = scan.sections || [];

const formLabel = body.form_name || 'All Forms';
const dateLabel = body.date_from ? `${body.date_from} to ${body.date_to}` : 'all available data';

const metricsContext = metrics.total_tickets > 0 ? `
SUPPORT METRICS (${formLabel}, ${dateLabel}):
- Total tickets: ${metrics.total_tickets}
- Solved tickets: ${metrics.solved_tickets}
- Avg resolution time: ${metrics.avg_resolution_hours != null ? metrics.avg_resolution_hours + ' hours' : 'N/A'}
- SLA breach rate: ${metrics.sla_breach_pct ?? 'N/A'}%
- Article link rate: ${metrics.article_link_pct ?? 'N/A'}%
- CSAT: ${metrics.csat_pct ?? 'N/A'}% good (${metrics.csat_responses ?? 0} actual responses out of ${metrics.total_tickets} tickets — low response rate is normal)` : '\nSUPPORT METRICS: No ticket data found for the selected filters.';

const kbContext = scan.scan_id ? `
KB GAP ANALYSIS (${scan.form_name}, ${scan.date_from} to ${scan.date_to}):
- Total tickets analyzed: ${scan.total_tickets}
- Topics tracked: ${scan.total_topics}
- Coverage score: ${scan.coverage_score}%
- KB availability gaps (no articles): ${scan.kb_availability} | KB linking gaps (articles unused): ${scan.kb_linking} | KB usage gaps (needs improvement): ${scan.kb_usage} | Non-KB topics: ${scan.non_kb}
- High priority topics: ${scan.high_priority} | Medium: ${scan.medium_priority}
- Est. deflection rate: ${scan.deflection_rate}%

ALL KB TOPICS (by volume):
${sections.map(s => `- ${s.topic_name}: ${s.ticket_count} tickets | ${s.gap_type} | ${s.priority} priority | KCS: ${s.kcs_adoption_pct}%
  Summary: ${s.gap_summary}
  Action: ${s.recommended_action}`).join('\n')}` : '\nKB GAP ANALYSIS: No scan data found for the selected filters.';

const systemPrompt = `You are a support intelligence assistant for Kipu Health. You have access to two data sources: live support ticket metrics and KB gap analysis. For every question, cross-reference both sources to surface insights neither could show alone — for example, connecting high SLA breach rates to missing KB articles, or linking CSAT dips to topics with no coverage. Always lead with the most actionable insight. Be concise and specific — cite ticket volumes, percentages, and topic names. If the data doesn't contain enough to answer, say so plainly.
${metricsContext}
${kbContext}`;

const historyMessages = history.map(h => `${h.role === 'user' ? 'User' : 'Assistant'}: ${h.content}`).join('\n');
const userPrompt = historyMessages ? `${historyMessages}\nUser: ${message}` : message;

return [{ json: { system_prompt: systemPrompt, user_prompt: userPrompt, original_message: message } }];

const llmOutput = $('Kipu LLM Webhook - Chat').first().json;
const response = llmOutput.output_text || llmOutput.text || llmOutput.response || '';
const usage = llmOutput.usage || { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 };
return [{ json: { response: String(response).trim(), usage } }];

const body = $('Webhook - Chat').first().json.body || $('Webhook - Chat').first().json;

const resp = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
const raw = resp?.output_text || '';
const cleaned = raw.replace(/```json|```/g, '').trim();

let extracted = { form_name: '', date_from: '', date_to: '' };
try {
  extracted = JSON.parse(cleaned);
} catch(e) {}

// Normalize dates to YYYY-MM-DD regardless of what format the LLM returned
const toISODate = val => {
  if (!val) return '';
  try {
    const d = new Date(val);
    if (isNaN(d.getTime())) return '';
    return d.toISOString().slice(0, 10);
  } catch(e) {
    return '';
  }
};

return [{ json: {
  message: body.message || '',
  history: body.history || [],
  form_name: extracted.form_name || '',
  date_from: toISODate(extracted.date_from),
  date_to: toISODate(extracted.date_to)
}}];

const allArticles = [];
for (const item of $input.all()) {
  const articles = item.json.articles || [];
  allArticles.push(...articles);
}

const filtered = allArticles.filter(a => {
  const categoryName = (a.category?.name || '').toLowerCase();
  return !categoryName.includes('release note');
});

const cleaned = filtered.map(a => {
  const bodyText = (a.body || '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 8000);

  return {
    article_id: a.id,
    title: a.title,
    body_text: bodyText,
    section_id: a.section_id,
    url: `https://kipuhealth.zendesk.com/hc/en-us/articles/${a.id}`,
    outdated: a.outdated || false,
    draft: a.draft || false,
    updated_at: a.updated_at,
    embed_input: `${a.title}\n\n${bodyText}`
  };
});

return [{ json: {
  inputs: cleaned.map(a => a.embed_input),
  articles: cleaned
}}];

const embeddings = $json.data || [];
const articles = $('Code - Filter + Clean Articles').first().json.articles;

return embeddings.map((e, i) => {
  const article = articles[i];
  if (!article) return null;
  return {
    json: {
      article_id: article.article_id,
      title: (article.title || '').replace(/'/g, "''"),
      body_text: (article.body_text || '').replace(/'/g, "''"),
      section_id: article.section_id || null,
      url: article.url,
      outdated: article.outdated || false,
      draft: article.draft || false,
      updated_at: article.updated_at,
      embedding: JSON.stringify(e.embedding),
      embedded_at: new Date().toISOString()
    }
  };
}).filter(Boolean);

const httpResult = $('HTTP - Fetch Articles').first().json;

return {
  json: {
    next_page: httpResult.next_page || null,
    has_more: !!httpResult.next_page
  }
};

const ticket = $('HTTP - Fetch Ticket').first().json.ticket;
const comments = $('HTTP - Fetch Ticket Comments').first().json.comments || [];

if (!ticket) throw new Error('Ticket not found');

const subject = ticket.subject || '';

// Get first 3 public comments (actual conversation, not just description)
const publicComments = comments
  .filter(c => c.public)
  .slice(0, 3)
  .map(c => c.body || '')
  .join('\n\n---\n\n')
  .slice(0, 2000);

const userPrompt = `Subject: ${subject}\n\nConversation:\n${publicComments || 'No comments available'}`;

return {
  json: {
    ticket_id: ticket.id,
    status: ticket.status,
    form_id: ticket.ticket_form_id,
    system_prompt: `You are a support ticket analyzer. Extract the core support question from the ticket below. Remove all personally identifiable information (names, emails, phone numbers, account numbers, dates of birth, facility names). Return only a 2-3 sentence plain English summary of the technical or functional issue being reported. No PHI, no metadata, just the question.`,
    user_prompt: userPrompt
  }
};

const summary = $json.output_text || $json.text || $json.response || '';
const ticket = $('Code - Prepare Ticket Text').item.json;

return {
  json: {
    ticket_id: ticket.ticket_id,
    status: ticket.status,
    form_id: ticket.form_id,
    summary: summary,
    embed_input: summary
  }
};

const results = $input.all().map(i => i.json);
const ticket = $('Code - Prepare Ticket Text').first().json;
const summary = $('Code - Extract Summary').first().json.summary;

const MIN_SIMILARITY = 0.5;
const filtered = results.filter(r => r.similarity >= MIN_SIMILARITY);

const bestMatch = filtered.length > 0 ? filtered[0] : null;

let coverage;
if (bestMatch && bestMatch.similarity >= 0.75) {
  coverage = 'covered';
} else if (bestMatch && bestMatch.similarity >= 0.60) {
  coverage = 'partial';
} else {
  coverage = 'none';
}

return [{
  json: {
    ticket_id: ticket.ticket_id,
    status: ticket.status,
    issue_summary: summary,
    coverage: coverage,
    coverage_label: coverage === 'covered'
      ? 'A relevant article exists for this topic'
      : coverage === 'partial'
      ? 'Partial match — review these articles'
      : 'No article found for this topic',
    articles: filtered.map(r => ({
      article_id: r.article_id,
      title: r.title,
      url: r.url,
      outdated: r.outdated,
      similarity: r.similarity,
      match_quality: r.similarity >= 0.75 ? 'strong' : 'possible'
    }))
  }
}];

parameters.query:
SELECT ticket_id, article_linked_flag
FROM support_ticket_metrics_fact
WHERE form_id = {{ $json.body.form_id }}
  AND ticket_created_at >= '{{ $json.body.date_from }}'
  AND ticket_created_at < '{{ $json.body.date_to }}'
ORDER BY ticket_id;

